func TestWalletExternalMessage_UnmarshalTLB(t *testing.T) {
	cell := boc.MustDeserializeSinglRootHex("")
	var extInMsg WalletExternalMessage
	if err := tlb.Unmarshal(cell, &extInMsg); err != nil {
		t.Fatalf("Unmarshal WalletExternalMessage: %v", err)
	}
	assert.Equal(t, tlb.Uint32(0), extInMsg.Message.SubwalletId)
	assert.Equal(t, tlb.Uint32(108), extInMsg.Message.MsgSeqno)
	assert.Equal(t, tlb.Uint32(1775834602), extInMsg.Message.ValidUntil)
	require.Len(t, extInMsg.Message.Forward, 1)
	assert.Equal(t, tlb.Uint8(0), extInMsg.Message.Forward[0].Mode)
	return
}

func TestWalletExternalMessage_ProxyRegister_UnmarshalTLB(t *testing.T) {
	originalExtData := ""
	cell := boc.MustDeserializeSinglRootHex(originalExtData)
	var extInMsg WalletExternalMessage
	if err := tlb.Unmarshal(cell, &extInMsg); err != nil {
		t.Fatalf("Unmarshal WalletExternalMessage: %v", err)
	}
	assert.Equal(t, tlb.Uint32(0), extInMsg.Message.SubwalletId)
	assert.Equal(t, tlb.Uint32(104), extInMsg.Message.MsgSeqno)
	assert.Equal(t, tlb.Uint32(1775834354), extInMsg.Message.ValidUntil)
	require.Len(t, extInMsg.Message.Forward, 1)
	assert.Equal(t, tlb.Uint8(0), extInMsg.Message.Forward[0].Mode)

	cellReenc, _ := extInMsg.ToCell()
	cellReencStr, _ := cellReenc.ToBocString()
	assert.Equal(t, originalExtData, cellReencStr)

	var walletOutMsg tlb.Message
	if err := tlb.Unmarshal(&extInMsg.Message.Forward[0].Msg, &walletOutMsg); err != nil {
		t.Fatalf("Unmarshal WalletExternalMessage.ForwardMessage[0]: %v", err)
	}
	require.True(t, walletOutMsg.Body.IsRight)
	clientInMsgCell := boc.Cell(walletOutMsg.Body.Value)

	var clientInMsg ClientMessage
	if err := tlb.Unmarshal(&clientInMsgCell, &clientInMsg); err != nil {
		t.Fatalf("Unmarshal WalletExternalMessage.ForwardMessage[0]: %v", err)
	}
	assert.Equal(t, ClientMessageKind_OwnerClientRegister, clientInMsg.SumType)
	assert.NotNil(t, clientInMsg.OwnerClientRegister)
	return
}

