func TestRootStorageDecode(t *testing.T) {
	cell := boc.MustDeserializeSinglRootHex("")

	var result RootStorage
	if err := tlb.Unmarshal(cell, &result); err != nil {
		t.Fatalf("Unmarshal RootStorage: %v", err)
	}

	if result.OwnerAddress == (tlb.InternalAddress{}) {
		t.Error("OwnerAddress is zero")
	}
	if result.Version == 0 {
		t.Error("Version is 0")
	}
	if result.Data.Value == nil {
		t.Fatal("Data.Value is nil")
	}
	if result.Params.Value == nil {
		t.Fatal("Params.Value is nil")
	}
	if result.Params.Value.StructVersion == 0 {
		t.Error("CocoonParams.StructVersion is 0")
	}
	if result.Params.Value.PricePerToken == 0 {
		t.Error("CocoonParams.PricePerToken is 0")
	}

	t.Logf("OwnerAddress: %v", result.OwnerAddress)
	t.Logf("Version: %d", result.Version)
	t.Logf("LastProxySeqno: %d", result.Data.Value.LastProxySeqno)
	t.Logf("StructVersion: %d", result.Params.Value.StructVersion)
	t.Logf("PricePerToken: %d", result.Params.Value.PricePerToken)
	t.Logf("ProxyHashes count: %d", len(result.Data.Value.ProxyHashes.Keys()))
	t.Logf("WorkerHashes count: %d", len(result.Data.Value.WorkerHashes.Keys()))
	t.Logf("ModelHashes count: %d", len(result.Data.Value.ModelHashes.Keys()))

	assert.True(t, result.Params.Value.WorkerScCode.Exists)
	assert.Equal(t, 80, result.Params.Value.WorkerScCode.Value.BitSize())

	proxies := result.Data.Value.RegisteredProxies
	t.Logf("RegisteredProxies count: %d", len(proxies.Keys()))

	for _, k := range proxies.Keys() {
		v, ok := proxies.Get(k)
		if !ok {
			t.Errorf("missing value for key %d", k)
			continue
		}
		if v.Address == "" {
			t.Errorf("RegisteredProxy[%d] has empty address", k)
		}
		t.Logf("RegisteredProxy[%d]: kind=%d address=%q", k, v.Kind, v.Address)
	}
}
